// Estado de conexión
let isOnline = flow.get("online");
if (isOnline === undefined) isOnline = true;

// Recuperar el estado anterior (si no existe, usar valores iniciales)
let lastState = flow.get("systemState") || {
    temperature: 24,
    humidity: 50,
    battery: 70,
    co: 0,
    hvac: false,
    generator: false,
    extinguisher: false,
    intruder: false,
    fire: false,
    door: "CERRADA",
    online: isOnline
};

// Recibir datos nuevos
let incomingData = msg.system || {}; 

// Estado actual combinado con el anterior
let currentState = { ...lastState, ...incomingData, online: isOnline };

// Detectar cambios
let changes = {};
let hasChanged = false;

// Comparar estado entrante vs. estado anterior
for (let key in incomingData) {
    if (incomingData[key] !== lastState[key]) {
        changes[key] = {
            from: lastState[key],
            to: incomingData[key]
        };
        hasChanged = true;
    }
}


// Guardar el estado y actualizar flujo solo cuando hay cambios
if (hasChanged) {
    currentState.lastUpdate = new Date().toISOString();
    flow.set("systemState", currentState);
}

msg.system = currentState;
msg.changes = changes;
msg.hasChanged = hasChanged;

return msg;

let msgEvent = {
    event: { type: "INTRUDER_TRIGGER" },
    topic: "event"
};

return msgEvent;

// Reset de timers (condición sostenida)
flow.set("fireTimer", null);
flow.set("batteryTimer", null);
flow.set("hvacTimer", null);

// Reset de simulación
flow.set("coTrigger", false);
flow.set("tempTrigger", false);
flow.set("batteryDrain", false);

// Reset de pop ups
flow.set("hvacNotified", false);
flow.set("generatorNotified", false);
flow.set("fireNotified", false);

// Reset de Flags
flow.set("intruderActive", false);
flow.set("activeMessage", null);

// Estado base
let system = {
    temperature: 24,
    humidity: 50,
    battery: 70,
    co: 0,
    hvac: false,
    generator: false,
    extinguisher: false,
    intruder: false,
    fire: false,
    door: "CERRADA",
    message: "🔄️ Sistema reiniciado",
    attempts: 0
};

// Pop up de reset
let notification = {
    payload: "🔄️ Sistema reiniciado correctamente."
}

// Guardar valores a nivel global
flow.set("system", system);
flow.set("temp_system", system);
flow.set("sim_state", system);

// Limpiar eventos
msg.event = null;

// Output
msg.system = system;

return [msg, notification];

let system = flow.get("system") || {
    attempts: 0
};

let credential = msg.payload.toString();

let event = null;
let notification = "";

// Validación de credenciales
if (credential.endsWith("E32")) {

    system.attempts = 0;

    event = { type: "ACCESS_GRANTED" };
    notification = "✅ Acceso autorizado";

} else {

    system.attempts += 1;

    if (system.attempts >= 3) {

        event = { type: "INTRUDER_TRIGGER" };
        notification = "🚨 ALERTA: Intruso detectado. Puerta bloqueada.";

    } else {

        event = { type: "ACCESS_DENIED" };
        notification = "❌ Acceso no autorizado";
    }
}

// Guardar estado global
flow.set("system", system);

// Output
msg.event = event;

msg.system = system;

msg.payload = notification;
msg.topic = "event";

return [msg];

let system = flow.get("system") || {
    temperature: 24,
    humidity: 50,
    battery: 70,
    co: 0,
    hvac: false,
    generator: false,
    extinguisher: false,
    intruder: false,
    fire: false,
    door: "CERRADA",
    message: "Normal",
    attempts: 0
};

// TELEMETRÍA
if (msg.topic === "telemetry" && msg.payload) {

    let allowed = ["temperature", "humidity", "battery", "co"];

    for (let key of allowed) {
        if (msg.payload[key] !== undefined) {
            system[key] = msg.payload[key];
        }
    }
}

// EVENTOS (ESP32)
// Acceso autorizado
if (msg.topic === "iot/access/granted") {
    msg.event = { type: "ACCESS_GRANTED" };
    msg.topic = "event";
}

// Acceso denegado
if (msg.topic === "iot/access/denied") {
    msg.event = { type: "ACCESS_DENIED" };
    msg.topic = "event";
    system.attempts += 1;
}

// Alerta de intruso
if (msg.topic === "iot/access/events" && msg.payload.intruder === true) {
    msg.event = { type: "INTRUDER_TRIGGER" };
    msg.topic = "event";
}

// OUTPUT
msg.system = system;

return msg;

// Valores iniciales
let sim = flow.get("sim_state") || {
    temperature: 24,
    humidity: 50,
    battery: 100,
    co: 0
};

let system = msg.system || flow.get("system") || {};
let now = Date.now();

// Timers de regreso a estado normal
let hvacOnSince = flow.get("hvacOnSince") || null;
let genOnSince = flow.get("genOnSince") || null;
let fireOnSince = flow.get("fireOnSince") || null;

// Triggers de eventos
let tempTrigger = flow.get("tempTrigger") || false;
let batteryDrain = flow.get("batteryDrain") || false;
let coTrigger = flow.get("coTrigger") || false;

// Incremento de temepratura y humedad (trigger)
if (tempTrigger && !system.hvac) {
    sim.temperature += 1;
    sim.humidity += 2;
}

// Decremento temperatura y humedad (regreso a valores iniciales)
if (system.hvac) {
    flow.set("tempTrigger", false);

    if (!hvacOnSince) {
        flow.set("hvacOnSince", now);
    }

    // Esperar 10 segundos
    if (now - hvacOnSince > 10000) {
        sim.temperature -= 1; 
        sim.humidity -= 2;
    }

} else {
    // reset cuando HVAC= OFF
    flow.set("hvacOnSince", null);
}

// Decremento batería (trigger)
if (batteryDrain) {
    sim.battery -= 5;
}

// Recarga de batería
if (system.generator) {
    flow.set("batteryDrain", false);

    if (!genOnSince) {
        genOnSince = now;
        flow.set("genOnSince", genOnSince);
    }

    if (now - genOnSince > 10000) {
        sim.battery += 1;
    }

} else {
    flow.set("genOnSince", null);
}

// Incremento de CO (incendio)
if (coTrigger) {
    sim.co += 4;
}

// Decremento de CO
if (system.extinguisher) {
    flow.set("coTrigger", false);

    if (!fireOnSince) {
        fireOnSince = now;
        flow.set("fireOnSince", fireOnSince);
    }

    if (now - fireOnSince > 10000) {
        sim.co -= 4;
    }

} else {
    flow.set("fireOnSince", null);
}


// Límites
sim.temperature = Math.max(23, Math.min(40, sim.temperature));
sim.humidity = Math.max(50, Math.min(82, sim.humidity));
sim.battery = Math.max(15, Math.min(100, sim.battery));
sim.co = Math.max(0, Math.min(70, sim.co));


// Guardar valores
flow.set("sim_state", sim);

// Output
msg.topic = "telemetry";
msg.payload = sim;
msg.system = system;

return msg;

if (msg.event) {
if (msg.event.type === "ACCESS_GRANTED") {
    msg.payload = "✅ Acceso autorizado";
    return msg;
}

if (msg.event.type === "INTRUDER_TRIGGER") {
    msg.payload = "🚨 ALERTA: Intruso detectado. Puerta bloqueada";
    return msg;
}
}



return null;

let system = msg.system;
let now = Date.now();

// --------------------
// IGNORAR SHADOW
// --------------------
if (msg.fromStateUpdate) {
    msg.system = system;
    return msg;
}

// Estado default de desired
msg.desired = {
    hvac: false,
    generator: false,
    extinguisher: false
};

// ====================
// 1. EVENTOS INMEDIATOS
// ====================

if (msg.event) {

    if (msg.event.type === "ACCESS_GRANTED") {
        flow.set("activeMessage", {
            text: "✅ Acceso autorizado",
            expires: now + 5000
        });

        flow.set("intruderActive", false);
        system.door = "ABIERTA";
    }

    if (msg.event.type === "ACCESS_DENIED") {
        flow.set("activeMessage", {
            text: "❌ Acceso no autorizado",
            expires: now + 5000
        });
    }

    if (msg.event.type === "INTRUDER_TRIGGER") {
        flow.set("activeMessage", {
            text: "🚨 Intruso detectado",
            expires: now + 5000
        });

        flow.set("intruderActive", true);
    }
}

// ====================
// 2. REAPLICAR ESTADO PERSISTENTE
// ====================

let intruderActive = flow.get("intruderActive") || false;

if (intruderActive) {
    system.intruder = true;
    system.door = "🚨BLOQUEADA";
} else {
    system.intruder = false;
}

// ====================
// 3. HVAC (condición sostenida)
// ====================

let hvacStart = flow.get("hvacStart") || null;

let hvacCondition =
    system.temperature > 32 ||
    system.temperature < 15 ||
    system.humidity > 80 ||
    system.humidity < 20;

if (hvacCondition) {

    if (!hvacStart) hvacStart = now;

    if (now - hvacStart > 5000) {
            msg.desired.hvac = true;
            if (!flow.get("hvacNotified")) {
                flow.set("hvacNotified", true);
            }
    }

} else {
    hvacStart = null;
    msg.desired.hvac = false;
    flow.set("hvacNotified", false);
}

flow.set("hvacStart", hvacStart);

// ====================
// 4. GENERADOR
// ====================

let genStart = flow.get("genStart") || null;

if (system.battery < 20) {

    if (!genStart) genStart = now;

    if (now - genStart > 5000) {

        msg.desired.generator = true;

        if (!flow.get("generatorNotified")) {
            flow.set("generatorNotified", true);
        }
    }    

} else {
    genStart = null;
    msg.desired.generator = false;
    flow.set("generatorNotified", false);
}

flow.set("genStart", genStart);

// ====================
// 5. INCENDIO
// ====================

let fireStart = flow.get("fireStart") || null;

if (system.co > 50) {

    if (!fireStart) fireStart = now;

    if (now - fireStart > 5000) {
        system.fire = true;

        msg.desired.extinguisher = true;

        if (!flow.get("fireNotified")) {
            flow.set("fireNotified", true);
        }
    }

} else {
    fireStart = null;
    system.fire = false;

    msg.desired.extinguisher = false;
    flow.set("fireNotified", false);
}

flow.set("fireStart", fireStart);

// ====================
// 6. PRIORIDAD: INCENDIO
// ====================

if (system.fire) {
    system.door = "ABIERTA";
    system.hvac = false;
    system.generator = false;
    system.message = "🔥 Evacuación por incendio";
} 

else if (intruderActive) {
    system.message = "🚨 Intruso detectado";
}

else {
    let active = flow.get("activeMessage");

    if (active && now < active.expires) {
        system.message = active.text;
    } else {
        system.message = "Normal";
    }
}

// Forzar siempre un mensaje
msg.desired = msg.desired || {};
msg.timestamp = Date.now(); 

// ====================
// OUTPUT
// ====================

msg.system = system;
flow.set("system", system);

return msg;

if (!msg.changes) return null;

if (msg.changes.hvac && msg.changes.hvac.to === true) {
    msg.payload = "⚠️ ADVERTENCIA: Temperatura/humedad fuera de rango. HVAC de emergencia activado.";
    return msg;
}

else if (msg.changes.hvac && msg.changes.hvac.to === false) {
    msg.payload = "✅ Temperatura/humedad dentro de rango seguro. HVAC de emergencia apagado.";
    return msg;
}

return null;

if (!msg.changes) return null;

if (msg.changes.generator && msg.changes.generator.to === true) {
    msg.payload = "⚠️ ADVERTENCIA: Batería de respaldo baja. Generador de emergencia activado.";
    return msg;
}

if (msg.changes.generator && msg.changes.generator.to === false) {
    msg.payload = "✅ Nivel de batería restaurada. Generador de emergencia apagado.";
    return msg;
}

if (!msg.changes) return null;

if (msg.changes.fire && msg.changes.fire.to === true) {
    msg.payload = "🚨 ALERTA: Incendio detectado. Evacuar inmediatamente.";
    let notification = {
        payload: "⚠️ ADVERTENCIA: Sistema de extinción tipo C activado."
    };
    return [msg,notification];
}

if (msg.changes.fire && msg.changes.fire.to === false) {
    msg.payload = "✅ Incendio controlado. Proceder con precaución.";
    let notification = {
        payload: "⚠️ Sistema de extinción tipo C apagado."
    };
    return [msg,notification];
}

return null;

let desired = msg.desired || {};
let last = flow.get("lastDesired") || {};

let diff = {};

// detectar cambios reales
for (let key in desired) {
    if (desired[key] !== last[key]) {
        diff[key] = desired[key];
    }
}

// guardar estado
flow.set("lastDesired", desired);

// si no hay cambios, no enviar
if (Object.keys(diff).length === 0) {
    return null;
}

// enviar SOLO cambios
msg.payload = {
    state: {
        desired: diff
    }
};

return msg;

// ====================
// 1. LEER DELTA
// ====================

let delta = msg.payload.state || {};

// ====================
// 2. OBTENER SYSTEM ACTUAL
// ====================

let system = flow.get("system") || {};

// ====================
// 3. APLICAR CAMBIOS (ACTUADORES)
// ====================

let reported = {};

if (delta.hvac !== undefined) {
    system.hvac = delta.hvac;
    reported.hvac = delta.hvac;
}

if (delta.generator !== undefined) {
    system.generator = delta.generator;
    reported.generator = delta.generator;
}

if (delta.extinguisher !== undefined) {
    system.extinguisher = delta.extinguisher;
    reported.extinguisher = delta.extinguisher;
}

// ====================
// 4. GUARDAR SYSTEM
// ====================

flow.set("system", system);

// ====================
// 5. PREPARAR REPORTE A AWS
// ====================

msg.payload = {
    state: {
        reported: reported
    }
};

// ====================
// 6. MARCAR COMO UPDATE DESDE SHADOW
// ====================

msg.system = system;
msg.fromStateUpdate = true;

// ====================
// DEBUG OPCIONAL
// ====================

node.warn("Actuadores aplicados: " + JSON.stringify(reported));

return msg;

let system = msg.system;
let now = Date.now();

let awsConnected = global.get("awsConnected") || true;
let mode = awsConnected ? "online" : "offline";

let events = [];

// Función dedupe (mismo evento en < 60s, no se envía)
function shouldSend(key) {
    const last = global.get("LAST_EVENT_SENT") || {};
    if (last[key] && (now - last[key]) < 10000) {
        return false; 
    }

    last[key] = now;
    global.set("LAST_EVENT_SENT", last);
    return true;
}

// Eventos con Shadow
if (system.hvac) {

    let key = "hvac_emergency_ON";

    if (shouldSend(key)) {
        events.push({
            eventType: "hvac_emergency",
            severity: "WARN",
            description: "Temperatura o humedad fuera de rango",
            source: "sensor_humidity_temp",
            measurements: {temp: system.temperature, humidity: system.humidity},
            actionsTaken: ["desired HVAC ON"],
            mode: mode,
            dedupeKey: key,
            timestamp: new Date().toISOString()
        });
    }
}

if (system.generator) {

    let key = "generator_low_battery";

    if (shouldSend(key)) {
        events.push({
            eventType: "generator_low_battery",
            severity: "WARN",
            description: "Batería < 20%",
            source: "sensor_battery",
            measurements: {battery: system.battery},
            actionsTaken: ["desired Generator ON"],
            mode: mode,
            dedupeKey: key,
            timestamp: new Date().toISOString()
        });
    }
}

if (system.extinguisher) {

    let key = "fire_extinguisher";

    if (shouldSend(key)) {
        events.push({
            eventType: "fire_extinguisher",
            severity: "CRITICAL",
            description: "Nivel de CO > 50 ppm",
            source: "sensor_CO",
            measurements: {CO: system.co},
            actionsTaken: ["desired Extinguisher ON"],
            mode: mode,
            dedupeKey: key,
            timestamp: new Date().toISOString()
        });
    }
}

// Eventos de emergencia inmediata
if (system.fire) {

    let key = "fire_alert";

    if (shouldSend(key)) {
        events.push({
            eventType: "fire_alert",
            severity: "CRITICAL",
            description: "Incendio detectado, activar evacuación",
            source: "sensor_CO",
            measurements: {CO: system.co},
            actionsTaken: ["alarma visual activada", "puerta abierta"],
            mode: mode,
            dedupeKey: key,
            timestamp: new Date().toISOString()
        });
    }
}

if (system.intruder) {

    let key = "intruder_alert";

    if (shouldSend(key)) {
        events.push({
            eventType: "intruder_alert",
            severity: "CRITICAL",
            description: "Intruso detectado, puerta bloqueada",
            source: "sensor_door",
            measurements: {},
            actionsTaken: ["alarma visual activada", "puerta bloqueada"],
            mode: mode,
            dedupeKey: key,
            timestamp: new Date().toISOString()
        });
    }
}

// Output 
msg.payload = events;
return msg;

let events = msg.payload;
let msgs = [];

events.forEach(event => {
    msgs.push({ payload: event });
});

return [msgs];
